    public function nonce() {
        return $this->milliseconds() - $this->options['timeDifference'];
    }

    public function fetch_time($params = array ()) {
        return $this->milliseconds();
    }

    public function load_time_difference($params = array ()) {
        $serverTime = $this->fetch_time($params);
        $after = $this->milliseconds();
        $this->options['timeDifference'] = $after - $serverTime;
        return $this->options['timeDifference'];
    }

    public function sign($path, $api = 'public', $method = 'GET', $params = array (), $headers = null, $body = null) {
        if (!(is_array($this->urls['api']) && array_key_exists($api, $this->urls['api']))) {
            throw new NotSupported($this->id . ' does not have a testnet/sandbox URL for ' . $api . ' endpoints');
        }
        $request = '/' . $this->implode_params($path, $params);
        $query = $this->omit($params, $this->extract_params($path));
        if ($method === 'GET') {
            if ($query) {
                $request .= '?' . $this->urlencode($query);
            }
        }
        if ($api === 'private') {
            if ($params['limit'] !== null) {
                $request .= '?' . $this->urlencode(array( 'limit' => $params['limit'], 'page' => $params['page'] ));
                unset($params['limit']);
                unset($params['page']);
            }
            $this->check_required_credentials();
            $nonce = intval($this->nonce() / 1000);
            $params = array_merge(array( 'timestamp' => $nonce, 'recvWindow' => 5000 ), $params);
            $hmac = $this->get_hmac_from_object($params);
            $body = $this->json($params);
            $headers = array(
                'apiKey' => $this->apiKey,
                'HMAC' => $hmac,
                'Content-Type' => 'application/json',
            );
        }
        $url = $this->urls['api'][$api] . $request;
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }

    public function fetch_balance($params = array ()) {
        $currency = $this->safe_string($params, 'currency');
        if ($currency === null) {
            $currency = 'ALL';
        } else {
            $currency = $this->currency_id($currency);
        }
        $params['currency'] = $currency;
        $response = $this->privatePostGetBalance ($params);
        $balances = $this->safe_value($response, 'data', array());
        $result = array( 'info' => $balances );
        for ($i = 0; $i < count($balances); $i++) {
            $currencyId = $this->safe_string($balances[$i], 'currency');
            $code = $this->safe_currency_code($currencyId);
            $account = $this->account();
            $free = $this->safe_float($balances[$i], 'balance');
            $used = $this->safe_float($balances[$i], 'balanceInTrade');
            $total = $free . $used;
            $account['total'] = $total;
            $account['free'] = $free;
            $account['used'] = $used;
            $result[$code] = $account;
        }
        return $this->parse_balance($result);
    }

    public function create_order($symbol, $type, $side, $amount, $price = null, $params = array ()) {
        $this->load_markets();
        $market = $this->market($symbol);
        $exchangeType = strtoupper($type);
        $exchangeSide = strtoupper($side);
        $baseId = explode('_', $market['id'])[1];
        $quoteId = explode('_', $market['id'])[0];
        $request = array(
            'market' => $quoteId,
            'trade' => $baseId,
            'side' => $exchangeSide,
            'type' => $exchangeType, // MARKET, LIMIT, STOPLIMIT
            'volume' => $this->amount_to_precision($symbol, $amount),
        );
        if ($exchangeType === 'LIMIT') {
            if ($price === null) {
                throw new InvalidOrder($this->id . ' createOrder method requires a $price argument for a ' . $type . ' order');
            }
            $request['rate'] = $this->price_to_precision($symbol, $price);
            $timeInForce = $this->safe_string($params, 'timeInForce');
            if ($timeInForce !== null) {
                if ($timeInForce !== 'GTC' && $timeInForce !== 'IOC' && $timeInForce !== 'FOK') {
                    $request['timeInForce'] = $timeInForce;
                }
            }
        }
        if ($exchangeType === 'STOPLIMIT') {
            $stopPrice = $this->safe_float($params, 'stopPrice');
            if ($price === null) {
                throw new InvalidOrder($this->id . ' createOrder method requires a $price argument for a ' . $type . ' order');
            }
            if ($stopPrice === null) {
                throw new InvalidOrder($this->id . ' createOrder method requires a stop argument for a ' . $type . ' order');
            }
            $request['rate'] = $this->price_to_precision($symbol, $price);
            $request['stop'] = $this->price_to_precision($symbol, $stopPrice);
        }
        if ($exchangeType === 'STOPMARKET') {
            $stopPrice = $this->safe_float($params, 'stopPrice');
            if ($stopPrice === null) {
                throw new InvalidOrder($this->id . ' createOrder method requires a stop argument for a ' . $type . ' order');
            }
            $request['stop'] = $this->price_to_precision($symbol, $stopPrice);
            $request['timeInForce'] = 'GTC';
        }
        if ($exchangeType === 'MARKET') {
            if ($price !== null) {
                throw new InvalidOrder($this->id . ' createOrder method does not support $price argument for a ' . $type . ' order');
            }
        }
        $response = $this->privatePostPlaceOrder ($request);
        //
        //     {
        //         status => 'Success',
        //         data => {
        //             "orderId" => 214083724
        //         }
        //    }
        //
        $timestamp = $this->seconds();
        $result = $this->safe_value($response, 'data');
        $id = $this->safe_integer($result, 'orderId');
        $order = array(
            'id' => $id,
            'info' => $response,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $symbol,
            'type' => $type,
            'side' => $side,
            'price' => $price,
            'amount' => $amount,
            'cost' => null,
            'average' => null,
            'filled' => null,
            'remaining' => null,
            'status' => null,
            'fee' => null,
            'trades' => null,
        );
        return $order;
    }

