    public function fetch_deposit_address($code, $params = array ()) {
        $this->load_markets();
        $currencies = $this->fetch_currencies();
        $currency = $this->safe_value($currencies, $code);
        if ($currency === null) {
            throw BadRequest ($this->id . ' fetchDepositAddress() error invalid currency');
        }
        $request = array(
            'currency' => $currency['id'],
        );
        $separator = strtolower($currency['info']['addressSeparator']);
        $response = $this->privatePostGenerateAddress ($request); // overwrite methods
        $result = $response['data'];
        $address = $this->safe_string($result, 'Address');
        $tag = '';
        if ($separator !== null && $separator !== '') {
            $s = strtolower(explode($separator, $address));
            $tag = $s[1];
            $address = $address->substr (
                0,
                strlen($s[0])
            );
        }
        $this->check_address($address);
        return array(
            'currency' => $code,
            'address' => $address,
            'tag' => $tag,
            'info' => $response,
        );
    }

