    public function fetch_markets($params = array ()) {
        $response = $this->publicGetApiGetSettings ();
        if ($this->options['adjustForTimeDifference']) {
            $this->load_time_difference();
        }
        $data = $this->safe_value($response, 'data');
        $res = $this->safe_value($data, 'trade_setting');
        $result = array();
        for ($i = 0; $i < count($res); $i++) {
            $market = $res[$i];
            $baseId = $this->safe_string($market, 'coinName');
            $quoteId = $this->safe_string($market, 'marketName');
            $id = $quoteId . '_' . $baseId;
            $base = $this->safe_currency_code($baseId);
            $quote = $this->safe_currency_code($quoteId);
            $symbol = $base . '/' . $quote;
            $active = $this->safe_value($market, 'tradeEnabled');
            $taker = $this->safe_float($market, 'takerFee');
            $maker = $this->safe_float($market, 'makerFee');
            $lotSize = $this->safe_float($market, 'minTradeAmount');
            $tickSize = $this->safe_float($market, 'minTickSize');
            $minCost = $this->safe_float($market, 'minOrderValue');
            // TODO => precision
            $result[] = array(
                'id' => $id,
                'symbol' => $symbol,
                'base' => $base,
                'quote' => $quote,
                'active' => $active,
                'precision' => array(
                    'amount' => $lotSize,
                    'price' => $tickSize,
                ),
                'taker' => $taker,
                'maker' => $maker,
                'limits' => array(
                    'amount' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'price' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'cost' => array(
                        'min' => $minCost,
                        'max' => null,
                    ),
                ),
                'info' => $market,
            );
        }
        return $result;
    }

