    public function fetch_currencies($params = array ()) {
        $response = $this->publicGetApiCurrencySettings ($params);
        $currencies = $this->safe_value($response, 'data');
        $result = array();
        for ($i = 0; $i < count($currencies); $i++) {
            $id = $this->safe_string($currencies[$i], 'shortName');
            // fees can have both percentage and flat fee
            $code = $this->safe_currency_code($id);
            $name = $this->safe_string($currencies[$i], 'fullName');
            $decimal = $this->safe_integer($currencies[$i], 'decimalPrecision');
            $precision = pow(10, -$decimal);
            // is $active only if all of the below are true
            $buyEnabled = $this->safe_value($currencies[$i], 'tradeEnabled_Buy');
            $sellEnabled = $this->safe_value($currencies[$i], 'tradeEnabled_Sell');
            $depositEnabled = $this->safe_value($currencies[$i], 'depositEnabled');
            $withdrawalEnabled = $this->safe_value($currencies[$i], 'withdrawalEnabled');
            $feeType = $this->safe_string($currencies[$i], 'withdrawalServiceChargeType');
            $flatFee = $this->safe_float($currencies[$i], 'withdrawalServiceCharge');
            $feePercentage = $this->safe_float($currencies[$i], 'withdrawalServiceChargeInBTC');
            if ($feeType === 'Percentage') {
                if ($feePercentage === 0) {
                    $feePercentage = $this->safe_float($currencies[$i], 'withdrawalServiceCharge');
                    $flatFee = 0;
                } else {
                    $feeType = 'Mixed';
                }
            }
            $active = $buyEnabled && $sellEnabled && $depositEnabled && $withdrawalEnabled;
            $result[$code] = array(
                'id' => $id,
                'code' => $code,
                'name' => $name,
                'active' => $active,
                // Warning => fee can be both percentage and flat. The `fee` field will have the flat one
                'fee' => $flatFee,
                'precision' => $precision,
                'limits' => array(
                    'amount' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'price' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'cost' => array(
                        'min' => null,
                        'max' => null,
                    ),
                    'withdraw' => array(
                        'min' => null,
                        'max' => null,
                    ),
                ),
                'info' => $currencies[$i],
                // custom
                'buyEnabled' => $buyEnabled,
                'sellEnabled' => $sellEnabled,
                'depositEnabled' => $depositEnabled,
                'withdrawalEnabled' => $withdrawalEnabled,
                'feeType' => $feeType, // Fixed | Percentage | Mixed
                'feePercentage' => $feePercentage,
            );
        }
        return $result;
    }

