    public function fetch_trades($symbol, $limit = null, $params = array ()) {
        $this->load_markets();
        $market = $this->market($symbol);
        $id = $market['id'];
        $request = array(
            'pair' => $id,
        );
        // WARNING => pagination not implemented yet. TODO
        $response = $this->publicGetMarketGetTradeHistoryPair (array_merge($request, $params));
        $result = $response['data'];
        $length = is_array($result) ? count($result) : 0;
        if ($length <= 0) {
            return array();
        }
        $normalizedTrades = array();
        for ($i = 0; $i < count($result); $i++) {
            $normalizedTrades[] = $this->normalize_trade_object($result[$i], $market);
        }
        return $this->parse_trades($normalizedTrades, $market);
    }

    public function fetch_ohlcv($symbol, $timeframe = '1m', $since = null, $limit = 100, $params = array ()) {
        $this->load_markets();
        $market = $this->market($symbol);
        $pair = $market['id'];
        $quote = explode('_', $pair)[0];
        $base = explode('_', $pair)[1];
        $minutes = $this->timeframes[$timeframe];
        if ($minutes === null) {
            $minutes = 1;
        }
        $oldSince = $since;
        if ($since === null) {
            $since = $this->milliseconds();
        } else {
            // recalculate the timestamp. The exchange expects the `until' timestamp instead of $since
            $since = $since . ($limit * ($minutes * (60 * 1000)));
        }
        $request = array(
            'baseCurrency' => $base,
            'quoteCurrency' => $quote,
            'interval' => $minutes,
            'timestamp' => $since,
            'limit' => $limit,
        );
        $response = $this->publicGetMarketGetChartData (array_merge($request, $params));
        $result = $this->safe_value($response, 'data', array());
        // revert $since to avoid the check in parseOHLCVs where candles outside the timestamp are removed
        $since = $oldSince;
        return $this->parse_ohlcvs($result, $market, $timeframe, $since, $limit);
    }

