    public function normalize_order_object($order) {
        return array(
            'orderId' => $order['OrderId'],
            'market' => $order['Market'],
            'trade' => $order['Trade'],
            'volume' => $order['Volume'],
            'pendingVolume' => $order['PendingVolume'],
            'orderStatus' => $order['Status'],
            'rate' => $order['Price'],
            'placementDate' => $order['PlacementDate'],
            'completionDate' => $order['CompletionDate'],
            'side' => $order['Side'],
            'type' => $order['Type'],
        );
    }

    public function parse_order($order, $market = null) {
        $side = $this->safe_string($order, 'side');
        if ($side !== null) {
            $side = strtolower($side);
        }
        $type = $this->safe_string($order, 'type');
        if ($type !== null) {
            $type = strtolower($type);
        }
        $marketCurrency = $this->safe_string($order, 'market');
        $tradeCurrency = $this->safe_string($order, 'trade');
        $marketId = $marketCurrency . '_' . $tradeCurrency;
        $market = $this->markets_by_id[$marketId];
        $orderStatus = $this->safe_value($order, 'orderStatus');
        $dateTime = null;
        if ($orderStatus) {
            // closed $order
            $dateTime = $this->safe_string($order, 'completionDate');
        } else {
            // open $order
            $dateTime = $this->safe_string($order, 'placementDate');
        }
        $timestamp = $this->parse8601($dateTime);
        $amount = $this->safe_float($order, 'volume');
        $remaining = $this->safe_float($order, 'pendingVolume');
        $filled = $amount - $remaining;
        $price = $this->safe_float($order, 'rate');
        $cost = $price * $filled;
        $symbol = null;
        if ($market !== null) {
            $symbol = $market['symbol'];
        }
        $status = $this->parse_order_status($orderStatus, $filled);
        $rawTrades = $this->safe_value($order, 'mOrders');
        $averagePrice = 0;
        $fee = 0;
        $trades = array();
        if ($rawTrades !== null && strlen($rawTrades) !== 0) {
            for ($i = 0; $i < count($rawTrades); $i++) {
                $tradePrice = $this->safe_float($rawTrades[$i], 'rate');
                $averagePrice .= $tradePrice;
                $tradeFee = $this->safe_float($rawTrades[$i], 'serviceCharge');
                $fee .= $tradeFee;
                $trades[] = $this->parse_trade($rawTrades[$i]);
            }
            $averagePrice = $averagePrice / is_array($trades) ? count($trades) : 0;
        }
        $id = $this->safe_value($order, 'orderId');
        return array(
            'id' => $id,
            'clientOrderId' => null,
            'info' => $order,
            'timestamp' => $timestamp,
            'datetime' => $dateTime,
            'lastTradeTimestamp' => null,
            'status' => $status,
            'symbol' => $symbol,
            'type' => $type,
            'side' => $side,
            'price' => $price,
            'cost' => $cost,
            'amount' => $amount,
            'filled' => $filled,
            'average' => $averagePrice,
            'remaining' => $remaining,
            'fee' => $fee,
            'trades' => $trades,
        );
    }

    public function parse_order_status($status, $filled) {
        $orderStatus = null;
        if (!$status) {
            $orderStatus = 'open';
        } else if ($filled === 0) {
            $orderStatus = 'canceled';
        } else {
            $orderStatus = 'closed';
        }
        return $orderStatus;
    }

    public function parse_ohlcv($ohlcv, $market = null) {
        return array(
            $this->safe_integer($ohlcv, 'time'),
            $this->safe_float($ohlcv, 'open'),
            $this->safe_float($ohlcv, 'high'),
            $this->safe_float($ohlcv, 'low'),
            $this->safe_float($ohlcv, 'close'),
            $this->safe_float($ohlcv, 'volume'),
        );
    }

    public function normalize_trade_object($trade, $market = null) {
        $id = $this->safe_value($trade, 'TradeID');
        $rate = $this->safe_float($trade, 'Rate');
        $volume = $this->safe_float($trade, 'Volume');
        $cost = $this->safe_float($trade, 'Total');
        $side = $this->safe_string($trade, 'Type');
        $date = $this->safe_string($trade, 'Date');
        $s = explode('_', $market['id']);
        $base = $s[1];
        $quote = $s[0];
        return array(
            'orderId' => (string) $id,
            'volume' => $volume,
            'rate' => $rate,
            'trade' => $base,
            'market' => $quote,
            'amount' => $cost,
            'serviceCharge' => null,
            'date' => $date,
            'side' => strtoupper($side),
        );
    }

    public function parse_trade($trade, $market = null) {
        $id = $this->safe_value($trade, 'orderId');
        $rate = $this->safe_float($trade, 'rate');
        $volume = $this->safe_float($trade, 'volume');
        $cost = $this->safe_float($trade, 'amount');
        $side = $this->safe_string($trade, 'side');
        $date = $this->safe_string($trade, 'date');
        $fee = $this->safe_float($trade, 'serviceCharge');
        $baseId = $this->safe_string($trade, 'trade');
        $quoteId = $this->safe_string($trade, 'market');
        $marketId = $quoteId . '_' . $baseId;
        $symbol = $this->markets_by_id[$marketId]['symbol'];
        $timestamp = $this->parse8601($date);
        return array(
            'id' => null,
            'order' => $id,
            'info' => $trade,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $symbol,
            'type' => null,
            'side' => strtolower($side),
            'takerOrMaker' => null,
            'price' => $rate,
            'amount' => $volume,
            'cost' => $cost,
            'fee' => $fee,
        );
    }

    public function parse_tickers($rawTickers, $market = null) {
        $tickers = array();
        $pairs = is_array($rawTickers) ? array_keys($rawTickers) : array();
        for ($i = 0; $i < count($pairs); $i++) {
            $symbol = $this->safe_symbol($pairs[$i]);
            $tickers[$symbol] = $this->parse_ticker($rawTickers[$pairs[$i]], $pairs[$i]);
        }
        return $tickers;
    }

    public function parse_ticker($ticker, $marketId = null) {
        $timestamp = $this->milliseconds();
        $symbol = $this->safe_symbol($marketId);
        $last = $this->safe_float($ticker, 'Last');
        return array(
            'symbol' => $symbol,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'high' => $this->safe_float($ticker, 'High_24hr'),
            'low' => $this->safe_float($ticker, 'Low_24hr'),
            'bid' => $this->safe_float($ticker, 'HeighestBid'),
            'bidVolume' => null,
            'ask' => $this->safe_float($ticker, 'LowestAsk'),
            'askVolume' => null,
            'vwap' => $this->safe_float($ticker, 'weightedAvgPrice'),
            'open' => $this->safe_float($ticker, 'openPrice'),
            'close' => $last,
            'last' => $last,
            'previousClose' => null,
            'change' => null,
            'percentage' => $this->safe_float($ticker, 'PercentChange'),
            'average' => null,
            'baseVolume' => $this->safe_float($ticker, 'QuoteVolume'),
            'quoteVolume' => $this->safe_float($ticker, 'BaseVolume'),
            'info' => $ticker,
        );
    }

    public function get_hmac_from_object($data) {
        $queryString = '';
        $keys = is_array($data) ? array_keys($data) : array();
        $keys->sort ();
        for ($i = 0; $i < count($keys); $i++) {
            $queryString .= $keys[$i] . '=' . $data[$keys[$i]];
            if ($i < strlen($keys) - 1) {
                $queryString .= '&';
            }
        }
        $hmac = $this->hmac($queryString, $this->secret, 'sha512', 'hex');
        $hmacString = strtoupper($hmac);
        return $hmacString;
    }
}
